 8. Particle System

A canvas-based particle system creates the floating dots effect:

const COLORS = ['rgba(0,229,255,', 'rgba(57,255,20,', 'rgba(255,107,53,'];
for (let i = 0; i < 55; i++) {
 pts.push({
 x: Math.random() * 2000,
 y: Math.random() * 1200,
 r: Math.random() * 1.4 + 0.4,
 vx: (Math.random() - .5) * 0.3,
 vy: (Math.random() - .5) * 0.3,
 col: COLORS[Math.floor(Math.random() * 3)],
 a: Math.random() * 0.5 + 0.15
 });
}

function draw() {
 ctx.clearRect(0, 0, W, H);
 pts.forEach(p => {
 p.x += p.vx; p.y += p.vy;
 // Wrap around edges
 if (p.x < 0) p.x = W; if (p.x > W) p.x = 0;
 if (p.y < 0) p.y = H; if (p.y > H) p.y = 0;
 // Draw particle
 ctx.beginPath();
 ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
 ctx.fillStyle = p.col + p.a + ')';
 ctx.fill();
 });
 // Draw connections
 for (let i = 0; i < pts.length; i++) {
 for (let j = i + 1; j < pts.length; j++) {
 const dist = Math.sqrt(dx * dx + dy * dy);
 if (dist < 120) {
 ctx.strokeStyle = 'rgba(0,229,255,' + (0.06 * (1 - dist / 120)) + ')';
 ctx.moveTo(pts[i].x, pts[i].y);
 ctx.lineTo(pts[j].x, pts[j].y);
 ctx.stroke();
 }
 }
 }
 requestAnimationFrame(draw);
}

